// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract ChainNotes {
    struct Note {
        uint id;
        string content;
        uint timestamp;
        address owner;
        bool isDeleted;
        string category;
        string[] tags;
    }

    uint public noteCount = 0;
    mapping(uint => Note) public notes;
    mapping(address => uint[]) public userNotes;

    event NoteCreated(uint id, address owner, string content, string category, string[] tags, uint timestamp);
    event NoteUpdated(uint id, string newContent, string newCategory, string[] newTags, uint timestamp);
    event NoteDeleted(uint id);

    modifier onlyOwner(uint _id) {
        require(notes[_id].owner == msg.sender, "Not the note owner");
        require(!notes[_id].isDeleted, "Note is deleted");
        _;
    }

    function createNote(
        string memory _content,
        string memory _category,
        string[] memory _tags
    ) public {
        noteCount++;

        Note storage note = notes[noteCount];
        note.id = noteCount;
        note.content = _content;
        note.timestamp = block.timestamp;
        note.owner = msg.sender;
        note.isDeleted = false;
        note.category = _category;
        note.tags = _tags;

        userNotes[msg.sender].push(noteCount);
        emit NoteCreated(noteCount, msg.sender, _content, _category, _tags, block.timestamp);
    }

    function updateNote(
        uint _id,
        string memory _newContent,
        string memory _newCategory,
        string[] memory _newTags
    ) public onlyOwner(_id) {
        Note storage note = notes[_id];
        note.content = _newContent;
        note.timestamp = block.timestamp;
        note.category = _newCategory;
        note.tags = _newTags;

        emit NoteUpdated(_id, _newContent, _newCategory, _newTags, block.timestamp);
    }

    function deleteNote(uint _id) public onlyOwner(_id) {
        notes[_id].isDeleted = true;
        emit NoteDeleted(_id);
    }

    function getUserNotes() public view returns (Note[] memory) {
        uint[] memory userNoteIds = userNotes[msg.sender];
        uint activeCount = 0;

        // Count active notes to size the array correctly
        for (uint i = 0; i < userNoteIds.length; i++) {
            if (!notes[userNoteIds[i]].isDeleted) {
                activeCount++;
            }
        }

        Note[] memory result = new Note[](activeCount);
        uint currentIndex = 0;

        // Populate the array with active notes
        for (uint i = 0; i < userNoteIds.length; i++) {
            if (!notes[userNoteIds[i]].isDeleted) {
                result[currentIndex] = notes[userNoteIds[i]];
                currentIndex++;
            }
        }

        return result;
    }
}
